questionText:
Dans le code suivant, quel est le rôle du composant <code>ThemeProvider</code> ?
```jsx
const ThemeContext = createContext('light');

function ThemeProvider({ children }) {
  return (
    &lt;ThemeContext.Provider value="dark"&gt;
      {children}
    &lt;/ThemeContext.Provider&gt;
  );
}
```

Que se passe-t-il dans ce code ?
```jsx
const CountContext = createContext();

function Parent() {
  const [count, setCount] = useState(0);
  return (
    &lt;CountContext.Provider value={count}&gt;
      &lt;Enfant /&gt;
    &lt;/CountContext.Provider&gt;
  );
}

function Enfant() {
  const count = useContext(CountContext);
  return &lt;div&gt;{count}&lt;/div&gt;;
}
```

Le code suivant ne fonctionne pas. Quelle est <strong>l'erreur</strong> ?
```jsx
const UserContext = createContext();

function App() {
  return (
    &lt;UserContext.Provider value={{ nom: 'Alice' }}&gt;
      &lt;Profil /&gt;
    &lt;/UserContext.Provider&gt;
  );
}

function Profil() {
  const { nom } = UserContext;
  return &lt;h1&gt;Bonjour {nom}&lt;/h1&gt;;
}
```
